371	enum SenderFlavor<T> {
372	    /// Bounded channel based on a preallocated array.
373	    Array(counter::Sender<flavors::array::Channel<T>>),
374	
375	    /// Unbounded channel implemented as a linked list.
376	    List(counter::Sender<flavors::list::Channel<T>>),
377	
378	    /// Zero-capacity channel.
379	    Zero(counter::Sender<flavors::zero::Channel<T>>),
380	}
381	
382	unsafe impl<T: Send> Send for Sender<T> {}
383	unsafe impl<T: Send> Sync for Sender<T> {}
384	
385	impl<T> UnwindSafe for Sender<T> {}
386	impl<T> RefUnwindSafe for Sender<T> {}
387	
388	impl<T> Sender<T> {
389	    /// Attempts to send a message into the channel without blocking.
390	    ///
391	    /// This method will either send a message into the channel immediately or return an error if
392	    /// the channel is full or disconnected. The returned error contains the original message.
393	    ///
394	    /// If called on a zero-capacity channel, this method will send the message only if there
395	    /// happens to be a receive operation on the other side of the channel at the same time.
396	    ///
397	    /// # Examples
398	    ///
399	    /// ```
400	    /// use crossbeam_channel::{bounded, TrySendError};
401	    ///
402	    /// let (s, r) = bounded(1);
403	    ///
404	    /// assert_eq!(s.try_send(1), Ok(()));
405	    /// assert_eq!(s.try_send(2), Err(TrySendError::Full(2)));
406	    ///
407	    /// drop(r);
408	    /// assert_eq!(s.try_send(3), Err(TrySendError::Disconnected(3)));
409	    /// ```
410	    pub fn try_send(&self, msg: T) -> Result<(), TrySendError<T>> {
411	        match &self.flavor {
412	            SenderFlavor::Array(chan) => chan.try_send(msg),
413	            SenderFlavor::List(chan) => chan.try_send(msg),
414	            SenderFlavor::Zero(chan) => chan.try_send(msg),
415	        }
416	    }
417	
418	    /// Blocks the current thread until a message is sent or the channel is disconnected.
419	    ///
420	    /// If the channel is full and not disconnected, this call will block until the send operation
421	    /// can proceed. If the channel becomes disconnected, this call will wake up and return an
422	    /// error. The returned error contains the original message.
423	    ///
424	    /// If called on a zero-capacity channel, this method will wait for a receive operation to
425	    /// appear on the other side of the channel.
426	    ///
427	    /// # Examples
428	    ///
429	    /// ```
430	    /// use std::thread;
431	    /// use std::time::Duration;
432	    /// use crossbeam_channel::{bounded, SendError};
433	    ///
434	    /// let (s, r) = bounded(1);
435	    /// assert_eq!(s.send(1), Ok(()));
436	    ///
437	    /// thread::spawn(move || {
438	    ///     assert_eq!(r.recv(), Ok(1));
439	    ///     thread::sleep(Duration::from_secs(1));
440	    ///     drop(r);
441	    /// });
442	    ///
443	    /// assert_eq!(s.send(2), Ok(()));
444	    /// assert_eq!(s.send(3), Err(SendError(3)));
445	    /// ```
446	    pub fn send(&self, msg: T) -> Result<(), SendError<T>> {
447	        match &self.flavor {
448	            SenderFlavor::Array(chan) => chan.send(msg, None),
449	            SenderFlavor::List(chan) => chan.send(msg, None),
450	            SenderFlavor::Zero(chan) => chan.send(msg, None),
451	        }
452	        .map_err(|err| match err {
453	            SendTimeoutError::Disconnected(msg) => SendError(msg),
454	            SendTimeoutError::Timeout(_) => unreachable!(),
455	        })
456	    }
457	
458	    /// Waits for a message to be sent into the channel, but only for a limited time.
459	    ///
460	    /// If the channel is full and not disconnected, this call will block until the send operation
461	    /// can proceed or the operation times out. If the channel becomes disconnected, this call will
462	    /// wake up and return an error. The returned error contains the original message.
463	    ///
464	    /// If called on a zero-capacity channel, this method will wait for a receive operation to
465	    /// appear on the other side of the channel.
466	    ///
467	    /// # Examples
468	    ///
469	    /// ```
470	    /// use std::thread;
471	    /// use std::time::Duration;
472	    /// use crossbeam_channel::{bounded, SendTimeoutError};
473	    ///
474	    /// let (s, r) = bounded(0);
475	    ///
476	    /// thread::spawn(move || {
477	    ///     thread::sleep(Duration::from_secs(1));
478	    ///     assert_eq!(r.recv(), Ok(2));
479	    ///     drop(r);
480	    /// });
481	    ///
482	    /// assert_eq!(
483	    ///     s.send_timeout(1, Duration::from_millis(500)),
484	    ///     Err(SendTimeoutError::Timeout(1)),
485	    /// );
486	    /// assert_eq!(
487	    ///     s.send_timeout(2, Duration::from_secs(1)),
488	    ///     Ok(()),
489	    /// );
490	    /// assert_eq!(
491	    ///     s.send_timeout(3, Duration::from_millis(500)),
492	    ///     Err(SendTimeoutError::Disconnected(3)),
